import javax.jws.WebService;
import javax.jws.WebMethod;
import javax.xml.ws.Holder;
import javax.xml.ws.soap.SOAPBinding;
import javax.xml.ws.soap.SOAPFaultException;
import javax.xml.soap.SOAPElement;
import javax.xml.soap.SOAPEnvelope;
import javax.xml.soap.SOAPHeader;
import javax.xml.soap.SOAPMessage;
import javax.xml.ws.WebServiceContext;
import javax.xml.ws.handler.MessageContext;
import java.util.Date;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.text.SimpleDateFormat;
import java.util.TimeZone;

@WebService
@SOAPBinding(style = SOAPBinding.Style.DOCUMENT, use = SOAPBinding.Use.LITERAL)
public class PaymentGatewayService {
    
    private static final Map<String, Date> processedTimestamps = new ConcurrentHashMap<>();
    private static final long TIMESTAMP_TOLERANCE = 300000; // 5 minutes
    
    @WebServiceContext
    private WebServiceContext context;
    
    @WebMethod
    public PaymentResponse processPayment(PaymentRequest request) {
        try {
            validateRequest(request);
            extractAndValidateTimestamp();
            
            PaymentResponse response = new PaymentResponse();
            response.setTransactionId(generateTransactionId());
            response.setStatus("SUCCESS");
            response.setAmount(request.getAmount());
            response.setCurrency(request.getCurrency());
            
            return response;
            
        } catch (Exception e) {
            throw new SOAPFaultException(e.getMessage());
        }
    }
    
    private void validateRequest(PaymentRequest request) throws Exception {
        if (request == null) {
            throw new Exception("Payment request cannot be null");
        }
        if (request.getAmount() == null || request.getAmount().compareTo(new java.math.BigDecimal("0")) <= 0) {
            throw new Exception("Invalid amount");
        }
        if (request.getCurrency() == null || request.getCurrency().isEmpty()) {
            throw new Exception("Currency is required");
        }
        if (request.getCardNumber() == null || request.getCardNumber().isEmpty()) {
            throw new Exception("Card number is required");
        }
        if (request.getExpiryDate() == null) {
            throw new Exception("Expiry date is required");
        }
    }
    
    private void extractAndValidateTimestamp() throws Exception {
        MessageContext msgContext = context.getMessageContext();
        Map<String, Object> headers = (Map<String, Object>) msgContext.get(MessageContext.HTTP_REQUEST_HEADERS);
        
        if (headers == null) {
            throw new Exception("Missing SOAP headers");
        }
        
        String timestamp = extractTimestampFromHeaders(headers);
        if (timestamp == null) {
            throw new Exception("Missing timestamp in SOAP header");
        }
        
        validateTimestamp(timestamp);
    }
    
    private String extractTimestampFromHeaders(Map<String, Object> headers) {
        Object timestampHeader = headers.get("Timestamp");
        if (timestampHeader instanceof java.util.List) {
            java.util.List<?> list = (java.util.List<?>) timestampHeader;
            if (!list.isEmpty()) {
                return list.get(0).toString();
            }
        }
        return timestampHeader != null ? timestampHeader.toString() : null;
    }
    
    private void validateTimestamp(String timestamp) throws Exception {
        try {
            SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
            sdf.setTimeZone(TimeZone.getTimeZone("UTC"));
            Date timestampDate = sdf.parse(timestamp);
            
            long currentTime = System.currentTimeMillis();
            long timestampMillis = timestampDate.getTime();
            
            if (Math.abs(currentTime - timestampMillis) > TIMESTAMP_TOLERANCE) {
                throw new Exception("Timestamp is outside acceptable range");
            }
            
            String timestampKey = timestampDate.toString();
            if (processedTimestamps.containsKey(timestampKey)) {
                throw new Exception("Replay attack detected - timestamp already used");
            }
            
            processedTimestamps.put(timestampKey, new Date());
            
        } catch (Exception e) {
            throw new Exception("Invalid timestamp format: " + e.getMessage());
        }
    }
    
    private String generateTransactionId() {
        return "TXN" + System.currentTimeMillis() + "_" + 
               java.util.UUID.randomUUID().toString().substring(0, 8);
    }
}

